Supports both sync dispatch (for backtest determinism) and async dispatch (for live trading).
"""

import asyncio
import logging
from collections import defaultdict
from collections.abc import Awaitable, Callable
from typing import Any

logger = logging.getLogger(__name__)

type SyncHandler = Callable[[Any], None]
type AsyncHandler = Callable[[Any], Awaitable[None]]
type Handler = SyncHandler | AsyncHandler


class EventBus:
    """Central event bus for inter-component communication."""

    def __init__(self) -> None:
        self._sync_handlers: dict[type, list[SyncHandler]] = defaultdict(list)
        self._async_handlers: dict[type, list[AsyncHandler]] = defaultdict(list)

    def subscribe(self, event_type: type, handler: Handler) -> None:
        """Subscribe a handler to an event type."""
        if asyncio.iscoroutinefunction(handler):
            self._async_handlers[event_type].append(handler)
        else:
            self._sync_handlers[event_type].append(handler)

    def unsubscribe(self, event_type: type, handler: Handler) -> None:
        """Unsubscribe a handler from an event type."""
        if asyncio.iscoroutinefunction(handler):
            handlers = self._async_handlers[event_type]
            if handler in handlers:
                handlers.remove(handler)
        else:
            handlers = self._sync_handlers[event_type]
            if handler in handlers:
                handlers.remove(handler)

    def publish_sync(self, event: object) -> None:
        """Publish an event synchronously. Used in backtest mode for determinism."""
        event_type = type(event)
        for handler in self._sync_handlers.get(event_type, []):
            try:
                handler(event)
            except Exception:
                logger.exception("Error in sync handler %s for %s", handler, event_type.__name__)

    async def publish_async(self, event: object) -> None:
        """Publish an event asynchronously. Used in live trading."""
        event_type = type(event)

        for handler in self._sync_handlers.get(event_type, []):
            try:
                handler(event)
            except Exception:
                logger.exception("Error in sync handler %s for %s", handler, event_type.__name__)

        tasks = []
        for handler in self._async_handlers.get(event_type, []):
            tasks.append(handler(event))

        if tasks:
            results = await asyncio.gather(*tasks, return_exceptions=True)
            for i, result in enumerate(results):
                if isinstance(result, Exception):
                    logger.exception(
                        "Error in async handler for %s",
                        event_type.__name__,
                        exc_info=result,
                    )

    def handler_count(self, event_type: type) -> int:
        """Return total number of handlers for an event type."""
        return len(self._sync_handlers.get(event_type, [])) + len(
            self._async_handlers.get(event_type, [])
        )

    def clear(self) -> None:
        """Remove all handlers."""
        self._sync_handlers.clear()
        self._async_handlers.clear()
