SystemClock returns real wall-clock time.
SimulatedClock allows manual time advancement for deterministic backtesting.
"""

from abc import ABC, abstractmethod
from datetime import datetime, timedelta, timezone


class Clock(ABC):
    """Abstract clock interface."""

    @abstractmethod
    def now(self) -> datetime:
        """Return the current timestamp (always UTC)."""

    @abstractmethod
    def is_simulated(self) -> bool:
        """Return True if this is a simulated clock."""


class SystemClock(Clock):
    """Real wall-clock time for live/paper trading."""

    def now(self) -> datetime:
        return datetime.now(timezone.utc)

    def is_simulated(self) -> bool:
        return False


class SimulatedClock(Clock):
    """Manually-controlled clock for backtesting."""

    def __init__(self, start_time: datetime | None = None) -> None:
        self._time = start_time or datetime(2020, 1, 1, tzinfo=timezone.utc)

    def now(self) -> datetime:
        return self._time

    def is_simulated(self) -> bool:
        return True

    def set_time(self, time: datetime) -> None:
        """Set the clock to a specific time."""
        self._time = time

    def advance(self, delta: timedelta) -> datetime:
        """Advance the clock by a timedelta and return the new time."""
        self._time += delta
        return self._time
