Thread-safe cache for latest bars, positions, orders, and other frequently accessed data.
"""

import threading
from collections import defaultdict, deque
from typing import Any


class Cache:
    """Thread-safe in-memory cache for hot trading data."""

    def __init__(self, max_bars: int = 1000) -> None:
        self._lock = threading.RLock()
        self._max_bars = max_bars
        self._bars: dict[str, deque[Any]] = defaultdict(lambda: deque(maxlen=self._max_bars))
        self._positions: dict[str, Any] = {}
        self._orders: dict[str, Any] = {}
        self._data: dict[str, Any] = {}

    def put_bar(self, symbol: str, bar: Any) -> None:
        """Store a bar event for a symbol."""
        with self._lock:
            self._bars[symbol].append(bar)

    def get_bars(self, symbol: str, count: int | None = None) -> list[Any]:
        """Get recent bars for a symbol."""
        with self._lock:
            bars = self._bars[symbol]
            if count is None:
                return list(bars)
            return list(bars)[-count:]

    def get_latest_bar(self, symbol: str) -> Any | None:
        """Get the most recent bar for a symbol."""
        with self._lock:
            bars = self._bars[symbol]
            return bars[-1] if bars else None

    def put_position(self, symbol: str, position: Any) -> None:
        """Store a position for a symbol."""
        with self._lock:
            self._positions[symbol] = position

    def get_position(self, symbol: str) -> Any | None:
        """Get the current position for a symbol."""
        with self._lock:
            return self._positions.get(symbol)

    def get_all_positions(self) -> dict[str, Any]:
        """Get all current positions."""
        with self._lock:
            return dict(self._positions)

    def put_order(self, order_id: str, order: Any) -> None:
        """Store an order by its ID."""
        with self._lock:
            self._orders[order_id] = order

    def get_order(self, order_id: str) -> Any | None:
        """Get an order by its ID."""
        with self._lock:
            return self._orders.get(order_id)

    def get_all_orders(self) -> dict[str, Any]:
        """Get all orders."""
        with self._lock:
            return dict(self._orders)

    def put(self, key: str, value: Any) -> None:
        """Store an arbitrary key-value pair."""
        with self._lock:
            self._data[key] = value

    def get(self, key: str) -> Any | None:
        """Get an arbitrary value by key."""
        with self._lock:
            return self._data.get(key)

    def clear(self) -> None:
        """Clear all cached data."""
        with self._lock:
            self._bars.clear()
            self._positions.clear()
            self._orders.clear()
            self._data.clear()
