Manages lifecycle FSM: PRE_INIT -> READY -> RUNNING -> STOPPED.
Wires all components to the EventBus.
"""

import logging

from vquant.core.cache import Cache
from vquant.core.clock import Clock, SimulatedClock, SystemClock
from vquant.core.enums import EngineState, TradingMode
from vquant.core.event_bus import EventBus

logger = logging.getLogger(__name__)


class EngineError(Exception):
    """Raised for invalid engine state transitions."""


class TradingEngine:
    """Top-level orchestrator for the vquant trading system."""

    def __init__(self, mode: TradingMode = TradingMode.BACKTEST) -> None:
        self._mode = mode
        self._state = EngineState.PRE_INIT
        self.event_bus = EventBus()
        self.cache = Cache()
        self.clock: Clock = SimulatedClock() if mode == TradingMode.BACKTEST else SystemClock()

    @property
    def mode(self) -> TradingMode:
        return self._mode

    @property
    def state(self) -> EngineState:
        return self._state

    def _transition(self, target: EngineState) -> None:
        valid_transitions: dict[EngineState, set[EngineState]] = {
            EngineState.PRE_INIT: {EngineState.READY},
            EngineState.READY: {EngineState.RUNNING, EngineState.STOPPED},
            EngineState.RUNNING: {EngineState.STOPPED},
            EngineState.STOPPED: set(),
        }
        if target not in valid_transitions[self._state]:
            raise EngineError(f"Invalid transition: {self._state} -> {target}")
        logger.info("Engine state: %s -> %s", self._state, target)
        self._state = target

    def initialize(self) -> None:
        """Initialize the engine and move to READY state."""
        self._transition(EngineState.READY)

    def start(self) -> None:
        """Start the engine and move to RUNNING state."""
        self._transition(EngineState.RUNNING)

    def stop(self) -> None:
        """Stop the engine and move to STOPPED state."""
        self._transition(EngineState.STOPPED)
        self.event_bus.clear()
        self.cache.clear()
