import os
import re
from pathlib import Path
from typing import Any

import yaml

from vquant.config.settings import AppSettings

_ENV_PATTERN = re.compile(r"\$\{(\w+)(?::([^}]*))?\}")


def _interpolate_env(value: str) -> str:
    """Replace ${ENV_VAR} or ${ENV_VAR:default} patterns with environment values."""

    def _replace(match: re.Match[str]) -> str:
        var_name = match.group(1)
        default = match.group(2)
        env_val = os.environ.get(var_name)
        if env_val is not None:
            return env_val
        if default is not None:
            return default
        return match.group(0)

    return _ENV_PATTERN.sub(_replace, value)


def _walk_and_interpolate(obj: Any) -> Any:
    """Recursively interpolate env vars in a nested dict/list structure."""
    if isinstance(obj, str):
        return _interpolate_env(obj)
    if isinstance(obj, dict):
        return {k: _walk_and_interpolate(v) for k, v in obj.items()}
    if isinstance(obj, list):
        return [_walk_and_interpolate(item) for item in obj]
    return obj


def load_yaml_config(path: Path) -> dict[str, Any]:
    """Load a YAML file and interpolate environment variables."""
    with open(path) as f:
        raw = yaml.safe_load(f) or {}
    return _walk_and_interpolate(raw)


def load_settings(config_path: Path | None = None) -> AppSettings:
    """Load AppSettings from YAML config (with env var interpolation) merged with env vars."""
    if config_path and config_path.exists():
        overrides = load_yaml_config(config_path)
        return AppSettings(**overrides)
    return AppSettings()
