from datetime import UTC, datetime
from decimal import Decimal

from vquant.core.enums import BarSize, Exchange
from vquant.core.events import BarEvent, TickEvent

_BINANCE_SYMBOL_MAP: dict[str, str] = {
    "BTCUSDT": "BTC/USDT",
    "ETHUSDT": "ETH/USDT",
    "BNBUSDT": "BNB/USDT",
    "SOLUSDT": "SOL/USDT",
    "XRPUSDT": "XRP/USDT",
    "DOGEUSDT": "DOGE/USDT",
}

_REVERSE_BINANCE: dict[str, str] = {v: k for k, v in _BINANCE_SYMBOL_MAP.items()}


def normalize_symbol(raw_symbol: str, exchange: Exchange) -> str:
    """Convert exchange-specific symbol to unified format (BASE/QUOTE)."""
    if "/" in raw_symbol:
        return raw_symbol.upper()

    match exchange:
        case Exchange.BINANCE:
            return _BINANCE_SYMBOL_MAP.get(raw_symbol.upper(), raw_symbol.upper())
        case Exchange.ALPACA:
            return raw_symbol.upper()
        case _:
            return raw_symbol.upper()


def to_exchange_symbol(unified_symbol: str, exchange: Exchange) -> str:
    """Convert unified symbol (BASE/QUOTE) to exchange-specific format."""
    match exchange:
        case Exchange.BINANCE:
            return _REVERSE_BINANCE.get(
                unified_symbol, unified_symbol.replace("/", "")
            )
        case Exchange.ALPACA:
            return unified_symbol.replace("/", "")
        case _:
            return unified_symbol


def normalize_bar(
    raw: dict[str, object],
    symbol: str,
    exchange: Exchange,
    bar_size: BarSize,
) -> BarEvent:
    """Convert raw bar data dict to BarEvent with UTC timestamp."""
    ts = raw.get("timestamp")
    if isinstance(ts, int | float):
        timestamp = datetime.fromtimestamp(ts / 1000 if ts > 1e12 else ts, tz=UTC)
    elif isinstance(ts, datetime):
        timestamp = ts if ts.tzinfo else ts.replace(tzinfo=UTC)
    elif isinstance(ts, str):
        timestamp = datetime.fromisoformat(ts)
        if timestamp.tzinfo is None:
            timestamp = timestamp.replace(tzinfo=UTC)
    else:
        timestamp = datetime.now(UTC)

    return BarEvent(
        symbol=normalize_symbol(symbol, exchange),
        exchange=exchange,
        bar_size=bar_size,
        timestamp=timestamp,
        open=Decimal(str(raw.get("open", 0))),
        high=Decimal(str(raw.get("high", 0))),
        low=Decimal(str(raw.get("low", 0))),
        close=Decimal(str(raw.get("close", 0))),
        volume=Decimal(str(raw.get("volume", 0))),
