import numpy as np
from numpy.typing import NDArray


class SMA:
    """Simple Moving Average.

    Supports both vectorized batch computation and incremental updates.
    """

    def __init__(self, period: int) -> None:
        if period < 1:
            raise ValueError("Period must be >= 1")
        self._period = period
        self._buffer: list[float] = []
        self._sum: float = 0.0

    @property
    def period(self) -> int:
        return self._period

    @property
    def value(self) -> float | None:
        """Current SMA value, or None if insufficient data."""
        if len(self._buffer) < self._period:
            return None
        return self._sum / self._period

    @property
    def ready(self) -> bool:
        return len(self._buffer) >= self._period

    def update(self, price: float) -> float | None:
        """Add a new price and return updated SMA value."""
        self._buffer.append(price)
        self._sum += price

        if len(self._buffer) > self._period:
            self._sum -= self._buffer[-self._period - 1]

        if len(self._buffer) < self._period:
            return None
        return self._sum / self._period

    def reset(self) -> None:
        self._buffer.clear()
        self._sum = 0.0

    @staticmethod
    def calculate(data: NDArray[np.float64], period: int) -> NDArray[np.float64]:
        """Vectorized SMA over an array. Returns NaN for insufficient data."""
        if len(data) < period:
            return np.full(len(data), np.nan)
        kernel = np.ones(period) / period
        result = np.convolve(data, kernel, mode="full")[:len(data)]
        result[:period - 1] = np.nan
        return result
