import numpy as np
from numpy.typing import NDArray


class EMA:
    """Exponential Moving Average.

    Uses the standard smoothing factor: alpha = 2 / (period + 1).
    """

    def __init__(self, period: int) -> None:
        if period < 1:
            raise ValueError("Period must be >= 1")
        self._period = period
        self._alpha = 2.0 / (period + 1)
        self._value: float | None = None
        self._count: int = 0
        self._sum: float = 0.0

    @property
    def period(self) -> int:
        return self._period

    @property
    def value(self) -> float | None:
        return self._value

    @property
    def ready(self) -> bool:
        return self._count >= self._period

    def update(self, price: float) -> float | None:
        """Add a new price and return updated EMA value."""
        self._count += 1

        if self._count < self._period:
            self._sum += price
            return None

        if self._count == self._period:
            self._sum += price
            self._value = self._sum / self._period
            return self._value

        # Standard EMA formula
        self._value = price * self._alpha + self._value * (1 - self._alpha)  # type: ignore[operator]
        return self._value

    def reset(self) -> None:
        self._value = None
        self._count = 0
        self._sum = 0.0

    @staticmethod
    def calculate(data: NDArray[np.float64], period: int) -> NDArray[np.float64]:
        """Vectorized EMA over an array. Returns NaN for insufficient data."""
        result = np.full(len(data), np.nan)
        if len(data) < period:
            return result

        alpha = 2.0 / (period + 1)
        # Seed with SMA
        result[period - 1] = np.mean(data[:period])
        for i in range(period, len(data)):
            result[i] = data[i] * alpha + result[i - 1] * (1 - alpha)
        return result
