        self._avg_loss: float | None = None
        self._gains: list[float] = []
        self._losses: list[float] = []
        self._count: int = 0

    @property
    def period(self) -> int:
        return self._period

    @property
    def value(self) -> float | None:
        if self._avg_gain is None:
            return None
        if self._avg_loss == 0:
            return 100.0
        rs = self._avg_gain / self._avg_loss  # type: ignore[operator]
        return 100.0 - (100.0 / (1.0 + rs))

    @property
    def ready(self) -> bool:
        return self._avg_gain is not None

    def update(self, price: float) -> float | None:
        """Add a new price and return updated RSI value."""
        if self._prev_price is None:
            self._prev_price = price
            return None

        change = price - self._prev_price
        self._prev_price = price
        gain = max(change, 0.0)
        loss = max(-change, 0.0)
        self._count += 1

        if self._count <= self._period:
            self._gains.append(gain)
            self._losses.append(loss)
            if self._count == self._period:
                self._avg_gain = sum(self._gains) / self._period
                self._avg_loss = sum(self._losses) / self._period
                return self.value
            return None

        # Wilder's smoothing
        self._avg_gain = (self._avg_gain * (self._period - 1) + gain) / self._period  # type: ignore[operator]
        self._avg_loss = (self._avg_loss * (self._period - 1) + loss) / self._period  # type: ignore[operator]
        return self.value

    def reset(self) -> None:
        self._prev_price = None
        self._avg_gain = None
        self._avg_loss = None
        self._gains.clear()
        self._losses.clear()
        self._count = 0

