import numpy as np
from numpy.typing import NDArray


class ATR:
    """Average True Range (Wilder's smoothing).

    Requires high, low, close for each bar.
    """

    def __init__(self, period: int = 14) -> None:
        if period < 1:
            raise ValueError("Period must be >= 1")
        self._period = period
        self._prev_close: float | None = None
        self._true_ranges: list[float] = []
        self._value: float | None = None
        self._count: int = 0

    @property
    def period(self) -> int:
        return self._period

    @property
    def value(self) -> float | None:
        return self._value

    @property
    def ready(self) -> bool:
        return self._value is not None

    def update(self, high: float, low: float, close: float) -> float | None:
        """Add a new bar and return updated ATR value."""
        if self._prev_close is None:
            self._prev_close = close
            tr = high - low
        else:
            tr = max(
                high - low,
                abs(high - self._prev_close),
                abs(low - self._prev_close),
            )
            self._prev_close = close

        self._count += 1

        if self._count <= self._period:
            self._true_ranges.append(tr)
            if self._count == self._period:
                self._value = sum(self._true_ranges) / self._period
                return self._value
            return None

        # Wilder's smoothing
        self._value = (self._value * (self._period - 1) + tr) / self._period  # type: ignore[operator]
        return self._value

    def reset(self) -> None:
        self._prev_close = None
        self._true_ranges.clear()
        self._value = None
        self._count = 0

    @staticmethod
    def calculate(
        high: NDArray[np.float64],
        low: NDArray[np.float64],
        close: NDArray[np.float64],
        period: int = 14,
    ) -> NDArray[np.float64]:
        """Vectorized ATR over arrays. Returns NaN for insufficient data."""
        n = len(high)
        result = np.full(n, np.nan)
        if n < period:
            return result

        # True Range
        tr = np.empty(n)
        tr[0] = high[0] - low[0]
        for i in range(1, n):
            tr[i] = max(
                high[i] - low[i],
                abs(high[i] - close[i - 1]),
                abs(low[i] - close[i - 1]),
            )

