        if not self.ready:
            return None
        mid, std = self._compute()
        return mid + self._num_std * std

    @property
    def middle(self) -> float | None:
        if not self.ready:
            return None
        mid, _ = self._compute()
        return mid

    @property
    def lower(self) -> float | None:
        if not self.ready:
            return None
        mid, std = self._compute()
        return mid - self._num_std * std

    def update(self, price: float) -> tuple[float, float, float] | None:
        """Add a new price. Returns (upper, middle, lower) or None."""
        self._buffer.append(price)

        if len(self._buffer) < self._period:
            return None

        mid, std = self._compute()
        return (
            mid + self._num_std * std,
            mid,
            mid - self._num_std * std,
        )

    def reset(self) -> None:
        self._buffer.clear()

    def _compute(self) -> tuple[float, float]:
        """Return (mean, std) of the last `period` values."""
        window = self._buffer[-self._period:]
        mean = sum(window) / self._period
        variance = sum((x - mean) ** 2 for x in window) / self._period
        return mean, math.sqrt(variance)

    @staticmethod
    def calculate(
        data: NDArray[np.float64],
        period: int = 20,
        num_std: float = 2.0,
    ) -> tuple[NDArray[np.float64], NDArray[np.float64], NDArray[np.float64]]:
        """Vectorized Bollinger Bands. Returns (upper, middle, lower)."""
        n = len(data)
        upper = np.full(n, np.nan)
        middle = np.full(n, np.nan)
        lower = np.full(n, np.nan)

        if n < period:
            return upper, middle, lower

        for i in range(period - 1, n):
            window = data[i - period + 1: i + 1]
            mid = np.mean(window)
            std = np.std(window)
            middle[i] = mid
            upper[i] = mid + num_std * std
            lower[i] = mid - num_std * std

        return upper, middle, lower
