from decimal import Decimal

from pydantic import Field

from vquant.core.enums import OrderSide
from vquant.core.events import BarEvent
from vquant.strategy.base import BaseStrategy, StrategyParams
from vquant.strategy.indicators.sma import SMA
from vquant.strategy.registry import register_strategy


class SMACrossoverParams(StrategyParams):
    fast_period: int = Field(default=10, ge=1)
    slow_period: int = Field(default=30, ge=1)


@register_strategy("sma_crossover")
class SMACrossoverStrategy(BaseStrategy):
    """SMA Crossover: buy when fast SMA crosses above slow SMA, sell when below."""

    Params = SMACrossoverParams

    def on_start(self) -> None:
        p = self._params if isinstance(self._params, SMACrossoverParams) else SMACrossoverParams()
        self._fast_sma: dict[str, SMA] = {}
        self._slow_sma: dict[str, SMA] = {}
        self._fast_period = p.fast_period
        self._slow_period = p.slow_period
        self._prev_fast: dict[str, float | None] = {}
        self._prev_slow: dict[str, float | None] = {}

    def on_bar(self, bar: BarEvent) -> None:
        symbol = bar.symbol
        close = float(bar.close)

        if symbol not in self._fast_sma:
            self._fast_sma[symbol] = SMA(self._fast_period)
            self._slow_sma[symbol] = SMA(self._slow_period)
            self._prev_fast[symbol] = None
            self._prev_slow[symbol] = None

        fast_val = self._fast_sma[symbol].update(close)
        slow_val = self._slow_sma[symbol].update(close)

        prev_fast = self._prev_fast[symbol]
        prev_slow = self._prev_slow[symbol]

        self._prev_fast[symbol] = fast_val
        self._prev_slow[symbol] = slow_val

        if fast_val is None or slow_val is None or prev_fast is None or prev_slow is None:
            return

        # Crossover detection
        if prev_fast <= prev_slow and fast_val > slow_val:
            self.emit_signal(symbol, OrderSide.BUY, Decimal("1"))
        elif prev_fast >= prev_slow and fast_val < slow_val:
            self.emit_signal(symbol, OrderSide.SELL, Decimal("1"))
